css:
body {
    font-family: 'Inter' !important;
    margin: 0;
    font-size:8px;
}

.invoice {
    background: #fff;
}

.top {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.business-info {
    display: flex;
    gap: 15px;
    align-items: center;
    font-size:10px;
    color:#666666;
}
.invoice-date{
    font-size:12px;
    color:#666666;
}
.invoice-date label{
    font-size:10px;
    color:#666666;
}
.logo {
    height: 50px;
    width:120px;
    object-fit:contain;
    margin-right:20px;
}

.right-info {
    text-align: right;
    font-size: 14px;
}

hr {
    margin: 25px 0;
    border: none;
    border-top: 2px solid #ddd;
}

h1 {
    margin: 0;
}

.subtitle {
    color: #777;
    margin-top: 5px;
}

.sections {
    display: flex;
    justify-content: space-between;
    margin-top: 30px;
    gap: 20px;
    font-size:11px;
}

.section {
    flex: 1;
    font-size: 11px;
}

.section h4 {
    margin-bottom: 10px;
    font-size: 11px;
    letter-spacing: 1px;
    color: #666;
    font-weight:normal;
}

.table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 30px;
}

.table th {
    text-align: left;
    font-size: 12px;
    color: #666;
    padding-bottom: 10px;
    border-bottom: 1px solid #ddd;
    vertical-align:middle;
}

.table td {
    padding: 12px 0;
    border-bottom: 1px solid #eee;
    font-size: 11px;
    vertical-align:middle;
}
.print-format td, .print-format th{
    vertical-align:middle !important;
}
.text-right {
    text-align: right;
}

.totals {
    margin-top: 20px;
    width: 50%;
    margin-left:auto;
    margin-right:0;
    font-size: 11px;
}
.print-format .totals td, .print-format .totals th{
    padding:3px !important;
}
.totals td {
    padding: 6px 0;
}

.total-due {
    font-weight: bold;
    font-size: 18px;
    padding-top: 10px;
    border-top: 2px solid #ddd;
}

.footer {
    margin-top: 40px;
    font-size: 12px;
    color: #777;
}

.footer a {
    color: #007bff;
    text-decoration: none;
}
.text-right{
    text-align:right !important;
}
.bank-account{
    margin-top:30px;
}
